const data = $input.first().json;
const campaigns = data.data || [];
return campaigns.map(c => ({
  json: {
    meta_id: c.id,
    name: c.name,
    objective: c.objective || null,
    status: c.status,
    buying_type: c.buying_type || null,
    daily_budget: c.daily_budget ? parseFloat(c.daily_budget) / 100 : null,
    lifetime_budget: c.lifetime_budget ? parseFloat(c.lifetime_budget) / 100 : null,
    start_date: c.start_time ? c.start_time.split('T')[0] : null,
    end_date: c.stop_time ? c.stop_time.split('T')[0] : null
  }
}));

const data = $input.first().json;
const insights = data.data || [];
const today = new Date().toISOString().split('T')[0];
return insights.map(row => {
  const leadAction = (row.actions || []).find(a => a.action_type === 'lead');
  const leadCpa = (row.cost_per_action_type || []).find(a => a.action_type === 'lead');
  return { json: {
    campaign_meta_id: row.campaign_id, date: today,
    impressions: parseInt(row.impressions || 0),
    clicks: parseInt(row.clicks || 0),
    spend: parseFloat(row.spend || 0),
    reach: parseInt(row.reach || 0),
    ctr: parseFloat(row.ctr || 0),
    cpc: parseFloat(row.cpc || 0),
    cpm: parseFloat(row.cpm || 0),
    conversions: leadAction ? parseInt(leadAction.value) : 0,
    cost_per_result: leadCpa ? parseFloat(leadCpa.value) : 0
  }};
});
